CREATE TABLE IF NOT EXISTS public.ubigeos (
    id BIGSERIAL PRIMARY KEY,
    codigo VARCHAR(6) NOT NULL UNIQUE,
    departamento VARCHAR(120) NOT NULL,
    provincia VARCHAR(120) NOT NULL,
    distrito VARCHAR(160) NOT NULL,
    cod_dep_inei VARCHAR(2),
    desc_dep_inei VARCHAR(120),
    cod_prov_inei VARCHAR(4),
    desc_prov_inei VARCHAR(120),
    cod_ubigeo_inei VARCHAR(6),
    desc_ubigeo_inei VARCHAR(160),
    cod_dep_reniec VARCHAR(2),
    desc_dep_reniec VARCHAR(120),
    cod_prov_reniec VARCHAR(4),
    desc_prov_reniec VARCHAR(120),
    cod_ubigeo_reniec VARCHAR(6),
    desc_ubigeo_reniec VARCHAR(160),
    cod_dep_sunat VARCHAR(2),
    desc_dep_sunat VARCHAR(120),
    cod_prov_sunat VARCHAR(4),
    desc_prov_sunat VARCHAR(120),
    cod_ubigeo_sunat VARCHAR(6),
    desc_ubigeo_sunat VARCHAR(160),
    created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
    version BIGINT NOT NULL DEFAULT 0
);

ALTER TABLE public.ubigeos
    ADD COLUMN IF NOT EXISTS cod_dep_inei VARCHAR(2),
    ADD COLUMN IF NOT EXISTS desc_dep_inei VARCHAR(120),
    ADD COLUMN IF NOT EXISTS cod_prov_inei VARCHAR(4),
    ADD COLUMN IF NOT EXISTS desc_prov_inei VARCHAR(120),
    ADD COLUMN IF NOT EXISTS cod_ubigeo_inei VARCHAR(6),
    ADD COLUMN IF NOT EXISTS desc_ubigeo_inei VARCHAR(160),
    ADD COLUMN IF NOT EXISTS cod_dep_reniec VARCHAR(2),
    ADD COLUMN IF NOT EXISTS desc_dep_reniec VARCHAR(120),
    ADD COLUMN IF NOT EXISTS cod_prov_reniec VARCHAR(4),
    ADD COLUMN IF NOT EXISTS desc_prov_reniec VARCHAR(120),
    ADD COLUMN IF NOT EXISTS cod_ubigeo_reniec VARCHAR(6),
    ADD COLUMN IF NOT EXISTS desc_ubigeo_reniec VARCHAR(160),
    ADD COLUMN IF NOT EXISTS cod_dep_sunat VARCHAR(2),
    ADD COLUMN IF NOT EXISTS desc_dep_sunat VARCHAR(120),
    ADD COLUMN IF NOT EXISTS cod_prov_sunat VARCHAR(4),
    ADD COLUMN IF NOT EXISTS desc_prov_sunat VARCHAR(120),
    ADD COLUMN IF NOT EXISTS cod_ubigeo_sunat VARCHAR(6),
    ADD COLUMN IF NOT EXISTS desc_ubigeo_sunat VARCHAR(160),
    ADD COLUMN IF NOT EXISTS version BIGINT NOT NULL DEFAULT 0;

